import{_ as a,o as r,c as t,al as o}from"./chunks/framework.BJsoK6mY.js";const u=JSON.parse('{"title":"Terminology","description":"","frontmatter":{},"headers":[],"relativePath":"guides/minecraft-server/terminology.md","filePath":"en/guides/minecraft-server/terminology.md","lastUpdated":null}'),i={name:"guides/minecraft-server/terminology.md"};function n(l,e,s,h,d,c){return r(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="terminology" tabindex="-1">Terminology <a class="header-anchor" href="#terminology" aria-label="Permalink to &quot;Terminology&quot;">​</a></h1><p>I know that especially when you are just starting to get into Game servers, the amount of new words can be quite overwhelming. I hope that this document can help you with that!</p><h2 id="general-terms" tabindex="-1">General Terms <a class="header-anchor" href="#general-terms" aria-label="Permalink to &quot;General Terms&quot;">​</a></h2><h3 id="client" tabindex="-1">Client <a class="header-anchor" href="#client" aria-label="Permalink to &quot;Client&quot;">​</a></h3><p>The client is effectively the game that you start on your local computer. Lets compare it to a plane for now.</p><h3 id="server" tabindex="-1">Server <a class="header-anchor" href="#server" aria-label="Permalink to &quot;Server&quot;">​</a></h3><p>An instance of Minecraft running in your terminal without a graphical preview, this is what your client connects to. You can imagine this like a big airport.</p><h3 id="terminal" tabindex="-1">Terminal <a class="header-anchor" href="#terminal" aria-label="Permalink to &quot;Terminal&quot;">​</a></h3><p>The Terminal, Console, Command Prompt or &quot;CMD&quot; is a Windows Application that lets you run &quot;commands&quot;. It lets you interact with apps that don&#39;t have a graphical user interface (GUI)</p><h3 id="vanilla" tabindex="-1">Vanilla <a class="header-anchor" href="#vanilla" aria-label="Permalink to &quot;Vanilla&quot;">​</a></h3><p>This word in general describes the unmodified version of a game, directly as it came from the game developer. This definition is not unique to Minecraft.</p><h3 id="server-software" tabindex="-1">Server Software <a class="header-anchor" href="#server-software" aria-label="Permalink to &quot;Server Software&quot;">​</a></h3><p>Once we want plugins and mods to work on our server, the vanilla <strong>server</strong> software will not be sufficient anymore. Therefore developers created their own &quot;Server Software&quot;, which includes all the features from the vanilla server as well new ones like plugin support.</p><h3 id="mod-loaders" tabindex="-1">Mod Loaders <a class="header-anchor" href="#mod-loaders" aria-label="Permalink to &quot;Mod Loaders&quot;">​</a></h3><p>Similar to Server Software, Mod Loaders describe modified Version of the vanilla <strong>client</strong> that include further features like mod support and performance</p>',15)])])}const p=a(i,[["render",n]]);export{u as __pageData,p as default};
